-- ═══════════════════════════════════════════════════════════
-- FGMN 카페 운영 — 완전 초기화 + 샘플 데이터
-- Supabase SQL 편집기에서 전체 실행
-- ═══════════════════════════════════════════════════════════

-- ── 0. 기존 테이블 삭제 (의존성 순서) ──────────────────────
DROP TABLE IF EXISTS checklist_logs CASCADE;
DROP TABLE IF EXISTS schedules        CASCADE;
DROP TABLE IF EXISTS checklists       CASCADE;
DROP TABLE IF EXISTS staffs           CASCADE;

-- ── 1. 테이블 생성 ──────────────────────────────────────────
CREATE TABLE staffs (
  id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  name         TEXT        NOT NULL,
  hourly_wage  INTEGER     NOT NULL DEFAULT 10320,
  is_active    BOOLEAN     NOT NULL DEFAULT true,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE checklists (
  id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  tab         TEXT        NOT NULL DEFAULT '오픈' CHECK (tab IN ('오픈','마감')),
  "order"     SMALLINT    NOT NULL DEFAULT 0,
  title       TEXT        NOT NULL,
  description TEXT,
  is_active   BOOLEAN     NOT NULL DEFAULT true,
  created_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE checklist_logs (
  id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  checklist_id UUID        NOT NULL REFERENCES checklists(id) ON DELETE CASCADE,
  staff_id     UUID        NOT NULL REFERENCES staffs(id)     ON DELETE CASCADE,
  log_date     DATE        NOT NULL DEFAULT CURRENT_DATE,
  is_completed BOOLEAN     NOT NULL DEFAULT false,
  checked_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE TABLE schedules (
  id             UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  staff_id       UUID        NOT NULL REFERENCES staffs(id) ON DELETE CASCADE,
  date           DATE        NOT NULL,
  shift_type     TEXT        CHECK (shift_type IN ('오픈','미들','마감')),
  recorded_hours NUMERIC(4,1) NOT NULL DEFAULT 0,
  start_time     TIME,
  end_time       TIME,
  note           TEXT,
  created_at     TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- ── 2. RLS 비활성화 (anon 키로 읽기/쓰기 허용) ─────────────
ALTER TABLE staffs         DISABLE ROW LEVEL SECURITY;
ALTER TABLE checklists     DISABLE ROW LEVEL SECURITY;
ALTER TABLE checklist_logs DISABLE ROW LEVEL SECURITY;
ALTER TABLE schedules      DISABLE ROW LEVEL SECURITY;

